import { useRef, useEffect } from "react";
import Message from "./Message";
import InputBox from "./InputBox";

function ChatWindow({ chat, onSend, loading }) {
    const chatRef = useRef(null);

    // Auto scroll to bottom
    useEffect(() => {
        chatRef.current?.scrollTo({
            top: chatRef.current.scrollHeight,
            behavior: "smooth",
        });
    }, [chat.messages, loading]);

    return (
        <div
            style={{
                flex: 1,
                display: "flex",
                flexDirection: "column",
                backgroundColor: "#f8fafc",
            }}
        >
            {/* CHAT AREA */}
            <div
                ref={chatRef}
                style={{
                    flex: 1,
                    overflowY: "auto",
                    padding: "32px 0",
                }}
            >
                <div
                    style={{
                        maxWidth: "900px",
                        margin: "0 auto",
                        padding: "0 16px",
                    }}
                >
                    {/* EMPTY STATE (LIKE REAL AI PLATFORMS) */}
                    {chat.messages.length === 0 && !loading && (
                        <div
                            style={{
                                marginTop: "30vh",
                                textAlign: "center",
                                fontSize: "22px",
                                color: "#6b7280",
                            }}
                        >
                            What can I help you with today?
                        </div>
                    )}

                    {/* MESSAGES */}
                    {chat.messages.map((msg, index) => (
                        <Message
                            key={index}
                            role={msg.role}
                            text={msg.text}
                        />
                    ))}

                    {/* TYPING INDICATOR */}
                    {loading && <Message role="ai" text="Thinking…" />}
                </div>
            </div>

            {/* INPUT */}
            <InputBox onSend={onSend} disabled={loading} />
        </div>
    );
}

export default ChatWindow;
